div.p:
c
TaggedPtr old_top;
old_top = atomic_load_explicit(
&stack->top,
memory_order_acquire
);

c
if (old_top.ptr == NULL) {
return {success: false, value: 0};
}
// old_top.ptr == &NodeA != NULL
// Continue...

c
// Hazard pointer protection (M4)
hp_protect(0, old_top.ptr);
// Validate protection is current
// (set-then-validate protocol)
// Read next pointer BEFORE CAS
new_top.ptr = old_top.ptr->next;
// new_top.ptr = &NodeB
new_top.version = old_top.version + 1;
// new_top.version = 6

c
bool success = atomic_compare_exchange_weak_explicit(
&stack->top,
&old_top,      // Updated on failure
new_top,
memory_order_release,  // Success
memory_order_acquire   // Failure
);
if (success) {
// LINEARIZATION POINT
// Pop is now visible to all threads
}

c
// CAS succeeded!
// Read value while we have reference
int64_t value = old_top.ptr->value;
// value = 42
// Release hazard protection
hp_release(0);
// Retire old node for safe reclamation
hp_retire(old_top.ptr);  // M4
return (PopResult){
.success = true,
.value = 42
};
